                      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3 max-h-64 overflow-y-auto border rounded-lg p-4">
                        {SKILLS_OPTIONS
                          .filter(skill => 
                            skill.toLowerCase().includes(skillsSearch.toLowerCase())
                          )
                          .map((skill) => (
                          <FormField
                            key={skill}
                            control={form.control}
                            name="keySkills"
                            render={({ field }) => {
                              return (
                                <FormItem
                                  key={skill}
                                  className="flex flex-row items-start space-x-3 space-y-0"
                                >
                                  <FormControl>
                                    <Checkbox
                                      checked={field.value?.includes(skill)}
                                      onCheckedChange={(checked) => {
                                        const currentSkills = Array.isArray(field.value) ? field.value : [];
                                        return checked
                                          ? field.onChange([...currentSkills, skill])
                                          : field.onChange(
                                              currentSkills.filter(
                                                (value) => value !== skill
                                              )
                                            )
                                      }}
