                      <FormItem>
                        <FormLabel>Social Impact</FormLabel>
                        <FormControl>
                          <StarRating 
                            value={field.value || 0} 
                            onChange={field.onChange}
                            data-testid="rating-edit-social-impact"
                          />
                        </FormControl>
