                            data-testid="rating-edit-strategy"
                          />
                        </FormControl>
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="marketing"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Marketing & Sales</FormLabel>
                        <FormControl>
                          <StarRating 
