import { Link, useLocation } from "wouter";
import { Button } from "@/components/ui/button";
import { Sheet, SheetContent, SheetTrigger } from "@/components/ui/sheet";
import { useAuth } from "@/hooks/useAuth";
import { Menu, LogOut } from "lucide-react";
import { useState } from "react";

export default function Navigation() {
  const [location] = useLocation();
  const { user } = useAuth();
  const [isOpen, setIsOpen] = useState(false);

  const isActive = (path: string) => location === path;

  const navigationItems = [
    { path: "/", label: "Home", testId: "nav-home" },
    { path: "/setup-skills", label: "Setup Skills", testId: "nav-setup" },
    { path: "/view-skills", label: "View Skills", testId: "nav-view" },
    { path: "/my-profile", label: "My Profile", testId: "nav-my-profile" },
  ];

  const adminItems = [
    { path: "/admin", label: "Admin", testId: "nav-admin" },
    { path: "/admin/users", label: "Manage Users", testId: "nav-manage-users" },
  ];

  const handleNavClick = () => {
    setIsOpen(false);
  };

  return (
    <header className="bg-card border-b border-border sticky top-0 z-50 safe-area-top">
      <div className="responsive-container">
        <div className="flex justify-between items-center h-16">
          {/* Logo/Brand - Responsive */}
          <div className="flex items-center space-x-2 sm:space-x-4 flex-shrink-0">
            <h1 className="font-caslon text-lg sm:text-xl md:text-2xl font-bold" data-testid="nav-title">
              St Basil's
            </h1>
            <span className="text-muted-foreground hidden sm:inline">|</span>
            <h2 className="font-brandon text-sm sm:text-base md:text-lg font-medium text-secondary hidden sm:block" data-testid="nav-subtitle">
              RE Skill Share
            </h2>
          </div>

          {/* Desktop Navigation */}
          <nav className="hidden lg:flex space-x-1">
            {navigationItems.map((item) => (
              <Link key={item.path} href={item.path}>
                <Button 
                  variant={isActive(item.path) ? "default" : "ghost"}
                  className="font-brandon font-medium nav-btn"
                  data-testid={item.testId}
                >
                  {item.label}
                </Button>
              </Link>
            ))}
            {user?.isAdmin && adminItems.map((item) => (
              <Link key={item.path} href={item.path}>
                <Button 
                  variant={isActive(item.path) ? "default" : "ghost"}
                  className="font-brandon font-medium nav-btn"
                  data-testid={item.testId}
                >
                  {item.label}
                </Button>
              </Link>
            ))}
          </nav>

          <div className="flex items-center space-x-2">
            {/* Desktop Logout Button */}
            <Button
              variant="ghost"
              size="sm"
              className="hidden lg:flex text-muted-foreground hover:text-foreground nav-btn"
              onClick={() => window.location.href = "/api/logout"}
              data-testid="button-logout"
            >
              <LogOut className="h-4 w-4" />
            </Button>

            {/* Mobile Menu */}
            <Sheet open={isOpen} onOpenChange={setIsOpen}>
              <SheetTrigger asChild>
                <Button
                  variant="ghost"
                  size="sm"
                  className="lg:hidden nav-btn"
                  data-testid="button-menu"
                >
                  <Menu className="h-5 w-5" />
                  <span className="sr-only">Toggle menu</span>
                </Button>
              </SheetTrigger>
              <SheetContent side="right" className="w-[280px] sm:w-[350px]">
                <div className="flex flex-col space-y-4 pt-6">
                  {/* Mobile Brand */}
                  <div className="pb-4 border-b border-border">
                    <h1 className="font-caslon text-xl font-bold" data-testid="mobile-nav-title">
                      St Basil's
                    </h1>
                    <h2 className="font-brandon text-base font-medium text-secondary" data-testid="mobile-nav-subtitle">
                      RE Skill Share
                    </h2>
                  </div>

                  {/* Mobile Navigation Items */}
                  <nav className="flex flex-col space-y-2">
                    {navigationItems.map((item) => (
                      <Link key={item.path} href={item.path} onClick={handleNavClick}>
                        <Button 
                          variant={isActive(item.path) ? "default" : "ghost"}
                          className="w-full justify-start font-brandon font-medium nav-btn"
                          data-testid={`mobile-${item.testId}`}
                        >
                          {item.label}
                        </Button>
                      </Link>
                    ))}

                    {user?.isAdmin && (
                      <>
                        <div className="pt-2 pb-1">
                          <div className="border-t border-border" />
                          <p className="text-xs text-muted-foreground font-brandon font-medium pt-2 px-3">
                            Administration
                          </p>
                        </div>
                        {adminItems.map((item) => (
                          <Link key={item.path} href={item.path} onClick={handleNavClick}>
                            <Button 
                              variant={isActive(item.path) ? "default" : "ghost"}
                              className="w-full justify-start font-brandon font-medium nav-btn"
                              data-testid={`mobile-${item.testId}`}
                            >
                              {item.label}
                            </Button>
                          </Link>
                        ))}
                      </>
                    )}
                  </nav>

                  {/* Mobile Logout Button */}
                  <div className="pt-4 border-t border-border">
                    <Button
                      variant="ghost"
                      className="w-full justify-start text-muted-foreground hover:text-foreground font-brandon font-medium nav-btn"
                      onClick={() => {
                        handleNavClick();
                        window.location.href = "/api/logout";
                      }}
                      data-testid="mobile-button-logout"
                    >
                      <LogOut className="h-4 w-4 mr-2" />
                      Log Out
                    </Button>
                  </div>
                </div>
              </SheetContent>
            </Sheet>
          </div>
        </div>
      </div>
    </header>
  );
}

client/src/components/PasswordProtection.content:
import { useState } from "react";
import { useMutation } from "@tanstack/react-query";
import { apiRequest } from "@/lib/queryClient";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { useToast } from "@/hooks/use-toast";

interface PasswordProtectionProps {
  onSuccess: () => void;
}

export default function PasswordProtection({ onSuccess }: PasswordProtectionProps) {
  const [password, setPassword] = useState("");
  const { toast } = useToast();

  const validatePassword = useMutation({
    mutationFn: async (password: string) => {
      const response = await apiRequest("POST", "/api/validate-password", { password });
      return response.json();
    },
    onSuccess: (data) => {
      if (data.valid) {
        onSuccess();
      } else {
        toast({
          title: "Access Denied",
          description: "Invalid password. Please try again.",
          variant: "destructive",
        });
        setPassword("");
      }
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: "Failed to validate password. Please try again.",
        variant: "destructive",
      });
      setPassword("");
    },
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (password.trim()) {
      validatePassword.mutate(password);
    }
  };

  return (
    <div className="min-h-screen bg-background flex items-center justify-center p-4">
      <div className="w-full max-w-md">
        <div className="text-center mb-8">
          <h1 className="font-caslon text-4xl font-bold text-foreground mb-2" data-testid="title-main">
            St Basil's
          </h1>
          <h2 className="font-brandon text-xl font-medium text-secondary mb-4" data-testid="title-subtitle">
            Redemptive Enterprise
          </h2>
          <p className="text-muted-foreground font-light" data-testid="text-description">
            Skill Share Portal
          </p>
        </div>

        <Card>
          <CardHeader>
            <CardTitle className="font-brandon font-medium text-lg" data-testid="card-title">
              Access Required
            </CardTitle>
            <p className="text-muted-foreground text-sm font-light" data-testid="card-description">
              Please enter the access password to continue
            </p>
          </CardHeader>
          <CardContent>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label htmlFor="password" className="block text-sm font-medium mb-2">
                  Password
                </label>
                <Input
                  id="password"
                  type="password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="Enter password"
                  required
                  data-testid="input-password"
                />
              </div>
              <Button 
                type="submit" 
                className="w-full" 
                disabled={validatePassword.isPending}
                data-testid="button-submit"
              >
                {validatePassword.isPending ? (
                  <>
                    <i className="fas fa-spinner fa-spin mr-2"></i>
                    Validating...
                  </>
                ) : (
                  "Enter"
                )}
              </Button>
            </form>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

client/src/components/SkillCard.tsx.content:
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import type { SkillProfile } from "@shared/schema";

interface SkillCardProps {
  profile: SkillProfile;
}

export default function SkillCard({ profile }: SkillCardProps) {
  const getTopSkills = (profile: SkillProfile) => {
    const skills = [
      { name: 'Strategy', value: profile.strategy, color: 'trust' },
      { name: 'Marketing', value: profile.marketing, color: 'community' },
      { name: 'Innovation', value: profile.innovation, color: 'accent' },
      { name: 'Leadership', value: profile.selfLeadership, color: 'growth' },
      { name: 'Operations', value: profile.operations, color: 'trust' },
      { name: 'Social Impact', value: profile.socialImpact, color: 'community' },
    ];

    return skills
      .filter(skill => skill.value && skill.value >= 4)
      .slice(0, 3);
  };

  const topSkills = getTopSkills(profile);

  const handleContact = () => {
    if (profile.contactMethod === 'email') {
      window.location.href = `mailto:${profile.email}`;
    } else if (profile.contactMethod === 'phone' && profile.phone) {
      window.location.href = `tel:${profile.phone}`;
    } else if (profile.contactMethod === 'whatsapp' && profile.phone) {
      window.open(`https://wa.me/${profile.phone.replace(/\D/g, '')}`, '_blank');
    } else {
      // Default to email if no other method available
      window.location.href = `mailto:${profile.email}`;
    }
  };

  return (
    <Card className="skill-card" data-testid={`skill-card-${profile.id}`}>
      <CardContent className="p-6">
        <div className="flex items-start justify-between mb-4">
          <div className="flex items-start space-x-4">
            {/* Profile Image */}
            <div className="w-16 h-16 rounded-full overflow-hidden bg-muted border-2 border-border flex-shrink-0 flex items-center justify-center">
              {profile.profileImageUrl ? (
                <img 
                  src={profile.profileImageUrl} 
                  alt={`${profile.name}'s profile`} 
                  className="w-full h-full object-cover"
                  data-testid="img-profile-card"
                />
              ) : (
                <div className="text-muted-foreground" data-testid="placeholder-profile-card">
                  <i className="fas fa-user text-xl"></i>
                </div>
              )}
            </div>

            <div>
              <h3 className="font-brandon font-medium text-lg" data-testid="text-profile-name">
                {profile.name}
              </h3>
              <p className="text-sm text-muted-foreground" data-testid="text-profile-occupation">
                {profile.occupation}
              </p>
            </div>
          </div>
          <Badge variant="outline" className="px-2 py-1 bg-growth/20 text-growth text-xs border-growth/30">
            <i className="fas fa-check-circle mr-1"></i>Verified
          </Badge>
        </div>

        <div className="mb-4">
          <p className="text-sm font-medium mb-2">Key Skills:</p>
          <div className="flex flex-wrap gap-1" data-testid="container-profile-skills">
            {Array.isArray(profile.keySkills) ? 
              profile.keySkills.slice(0, 5).map((skill, index) => (
                <span 
                  key={index}
                  className="text-xs bg-muted px-2 py-1 rounded-full border"
                  data-testid={`skill-tag-${skill.toLowerCase().replace(/[^a-z0-9]/g, '-')}`}
                >
                  {skill}
                </span>
              )) :
              <p className="text-sm text-muted-foreground font-light" data-testid="text-profile-skills">
                {profile.keySkills}
              </p>
            }
            {Array.isArray(profile.keySkills) && profile.keySkills.length > 5 && (
              <span className="text-xs text-muted-foreground px-2 py-1">
                +{profile.keySkills.length - 5} more
              </span>
            )}
          </div>
        </div>

        {topSkills.length > 0 && (
          <div className="mb-4">
            <p className="text-sm font-medium mb-2">Top Expertise Areas:</p>
            <div className="flex flex-wrap gap-1">
              {topSkills.map((skill, index) => (
                <Badge 
                  key={index}
                  variant="secondary" 
                  className={`px-2 py-1 text-xs ${
                    skill.color === 'trust' ? 'bg-trust/20 text-trust border-trust/30' :
                    skill.color === 'community' ? 'bg-community/20 text-community border-community/30' :
                    skill.color === 'growth' ? 'bg-growth/20 text-growth border-growth/30' :
                    'bg-accent text-accent-foreground'
                  }`}
                  data-testid={`badge-skill-${skill.name.toLowerCase().replace(' ', '-')}`}
                >
                  {skill.name}
                </Badge>
              ))}
            </div>
          </div>
        )}

        <div className="flex justify-between items-center pt-4 border-t border-border">
          <div className="text-xs text-muted-foreground" data-testid="text-weekly-hours">
            {profile.weeklyHours === '0' ? 'No availability' : `${profile.weeklyHours}/week`}
          </div>
          <Button 
            size="sm"
            onClick={handleContact}
            data-testid="button-contact"
          >
            Contact
          </Button>
        </div>
      </CardContent>
    </Card>
  );
}

client/src/components/SkillsForm.tsx.content:
import { useState } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { useMutation } from "@tanstack/react-query";
import { apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { isUnauthorizedError } from "@/lib/authUtils";
import { insertSkillProfileSchema, type InsertSkillProfile } from "@shared/schema";
import { z } from "zod";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Checkbox } from "@/components/ui/checkbox";
import StarRating from "./StarRating";
import ImageUpload from "./ImageUpload";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";

const formSchema = insertSkillProfileSchema.extend({
  name: z.string().min(1, "Name is required"),
  email: z.string().email("Valid email is required"),
  occupation: z.string().min(1, "Occupation is required"),
  keySkills: z.array(z.string()).min(1, "Please select at least one skill"),
  contactMethod: z.string().optional(),
  isMember: z.string().min(1, "Please select membership status"),
});

import { SKILLS_OPTIONS } from "@/constants/skills";

type FormData = z.infer<typeof formSchema>;

export default function SkillsForm() {
  const { toast } = useToast();
  const [showSuccessModal, setShowSuccessModal] = useState(false);
  const [skillsSearch, setSkillsSearch] = useState("");

  const form = useForm<FormData>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      name: "",
      isMember: "",
      occupation: "",
      keySkills: [],
      expertiseToShare: "",
      contactMethod: "",
      email: "",
      phone: "",
      weeklyHours: "0",
      selfLeadership: 0,
      cultureTeam: 0,
      socialImpact: 0,
      innovation: 0,
      strategy: 0,
      marketing: 0,
      operations: 0,
      fundraising: 0,
      agreeToContact: false,
      agreeToRENews: false,
      profileImageUrl: "",
      integratesFaith: "",
      faithIntegrationEase: "",
      cause: "",
      peopleGroup: "",
      passionateIssue: "",
      passionateCountry: "",
    },
  });

  const createProfile = useMutation({
    mutationFn: async (data: FormData) => {
      const response = await apiRequest("POST", "/api/skill-profiles", data);
      return response.json();
    },
    onSuccess: () => {
      setShowSuccessModal(true);
      form.reset();
    },
    onError: (error) => {
      if (isUnauthorizedError(error)) {
        toast({
          title: "Unauthorized",
          description: "You are logged out. Logging in again...",
          variant: "destructive",
        });
        setTimeout(() => {
          window.location.href = "/api/login";
        }, 500);
        return;
      }
      toast({
        title: "Error",
        description: "Failed to submit profile. Please try again.",
        variant: "destructive",
      });
    },
  });

  const onSubmit = (data: FormData) => {
    createProfile.mutate(data);
  };

  return (
    <>
      <Form {...form}>
        <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-8" data-testid="form-skills">
          {/* Personal Information */}
          <Card>
            <CardHeader>
              <CardTitle className="font-brandon font-medium text-xl" data-testid="title-personal-info">
                Personal Information
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-6">
              {/* Profile Image Upload */}
              <div className="flex justify-center">
                <ImageUpload
                  currentImageUrl={form.watch("profileImageUrl")}
                  onImageUploaded={(imageUrl) => form.setValue("profileImageUrl", imageUrl)}
                  className="w-full"
                />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <FormField
                  control={form.control}
                  name="name"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Full Name *</FormLabel>
                      <FormControl>
                        <Input 
                          placeholder="Enter your full name" 
                          {...field} 
                          data-testid="input-name"
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="isMember"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Is St Basils your home? *</FormLabel>
                      <Select onValueChange={field.onChange} defaultValue={field.value}>
                        <FormControl>
                          <SelectTrigger data-testid="select-member-status">
                            <SelectValue placeholder="Please select..." />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="yes">Yes</SelectItem>
                          <SelectItem value="no">No</SelectItem>
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </div>

              <FormField
                control={form.control}
                name="occupation"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Current Occupation *</FormLabel>
                    <FormControl>
                      <Input 
                        placeholder="e.g., Software Developer, Teacher, Business Owner" 
                        {...field} 
                        data-testid="input-occupation"
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </CardContent>
          </Card>

          {/* Skills Assessment */}
          <Card>
            <CardHeader>
              <CardTitle className="font-brandon font-medium text-xl" data-testid="title-skills-assessment">
                Skills Assessment
              </CardTitle>
              <p className="text-muted-foreground text-sm font-light">
                Rate your proficiency in each area (0 = No experience, 1 = Beginner, 5 = Highly proficient)
              </p>
            </CardHeader>
            <CardContent>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <FormField
                  control={form.control}
                  name="selfLeadership"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Self Leadership</FormLabel>
                      <FormControl>
                        <StarRating 
                          value={field.value} 
                          onChange={field.onChange}
                          data-testid="rating-self-leadership"
                        />
                      </FormControl>
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="cultureTeam"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Culture, Team & Values</FormLabel>
                      <FormControl>
                        <StarRating 
                          value={field.value} 
                          onChange={field.onChange}
                          data-testid="rating-culture-team"
                        />
                      </FormControl>
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="socialImpact"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Social Impact</FormLabel>
                      <FormControl>
                        <StarRating 
                          value={field.value} 
                          onChange={field.onChange}
                          data-testid="rating-social-impact"
                        />
                      </FormControl>
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="innovation"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Innovation, Imagination</FormLabel>
                      <FormControl>
                        <StarRating 
                          value={field.value} 
                          onChange={field.onChange}
                          data-testid="rating-innovation"
                        />
                      </FormControl>
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="strategy"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Strategy, Business Model</FormLabel>
                      <FormControl>
                        <StarRating 
                          value={field.value} 
                          onChange={field.onChange}
                          data-testid="rating-strategy"
                        />
                      </FormControl>
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="marketing"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Marketing, Sales</FormLabel>
                      <FormControl>
                        <StarRating 
                          value={field.value} 
                          onChange={field.onChange}
                          data-testid="rating-marketing"
                        />
                      </FormControl>
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="operations"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Operating Model</FormLabel>
                      <FormControl>
                        <StarRating 
                          value={field.value} 
                          onChange={field.onChange}
                          data-testid="rating-operations"
                        />
                      </FormControl>
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="fundraising"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Fundraising & Governance</FormLabel>
                      <FormControl>
                        <StarRating 
                          value={field.value} 
                          onChange={field.onChange}
                          data-testid="rating-fundraising"
                        />
                      </FormControl>
                    </FormItem>
                  )}
                />
              </div>
            </CardContent>
          </Card>

          {/* Key Skills Selection */}
          <Card>
            <CardHeader>
              <CardTitle className="font-brandon font-medium text-xl" data-testid="title-key-skills">
                What are your key skill sets?
              </CardTitle>
              <p className="text-muted-foreground text-sm font-light">
                Select all skills that apply to you. Choose the areas where you have experience or expertise.
              </p>
            </CardHeader>
            <CardContent>
              <FormField
                control={form.control}
                name="keySkills"
                render={() => (
                  <FormItem>
                    {/* Search Box */}
                    <div className="mb-4">
                      <Input
                        placeholder="Search skills..."
                        value={skillsSearch}
                        onChange={(e) => setSkillsSearch(e.target.value)}
                        className="max-w-md"
                        data-testid="input-skills-search"
                      />
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3 max-h-96 overflow-y-auto border rounded-lg p-4">
                      {SKILLS_OPTIONS
                        .filter(skill => 
                          skill.toLowerCase().includes(skillsSearch.toLowerCase())
                        )
                        .map((skill) => (
                        <FormField
                          key={skill}
                          control={form.control}
                          name="keySkills"
                          render={({ field }) => {
                            return (
                              <FormItem
                                key={skill}
                                className="flex flex-row items-start space-x-3 space-y-0"
                              >
                                <FormControl>
                                  <Checkbox
                                    checked={field.value?.includes(skill)}
                                    onCheckedChange={(checked) => {
                                      return checked
                                        ? field.onChange([...field.value, skill])
                                        : field.onChange(
                                            field.value?.filter(
                                              (value) => value !== skill
                                            )
                                          )
                                    }}
                                    data-testid={`checkbox-skill-${skill.toLowerCase().replace(/[^a-z0-9]/g, '-')}`}
                                  />
                                </FormControl>
                                <FormLabel className="text-sm font-normal">
                                  {skill}
                                </FormLabel>
                              </FormItem>
                            )
                          }}
                        />
                      ))}
                    </div>
                    <FormMessage />
                  </FormItem>
                )}
              />

              {/* Expertise to Share */}
              <div className="mt-6">
                <FormField
                  control={form.control}
                  name="expertiseToShare"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>What are you highly proficient in?</FormLabel>
                      <FormControl>
                        <Textarea 
                          placeholder="Is there anything that you are highly proficient in and would be willing to share/present to our Redemptive Enterprise Network?"
                          className="h-24 resize-none"
                          {...field}
                          value={field.value || ""} 
                          data-testid="textarea-expertise-share"
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </div>
            </CardContent>
          </Card>

          {/* Faith Integration & Calling */}
          <Card>
            <CardHeader>
              <CardTitle className="font-brandon font-medium text-xl" data-testid="title-faith-calling">
                Faith Integration & Calling
              </CardTitle>
              <p className="text-muted-foreground text-sm font-light">
                Help us understand how your faith intersects with your work and calling
              </p>
            </CardHeader>
            <CardContent className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <FormField
                  control={form.control}
                  name="integratesFaith"
                  render={({ field }) => (
                    <FormItem className="flex flex-col h-full">
                      <FormLabel className="form-label-fixed">Do you integrate your faith into your work life?</FormLabel>
                      <Select onValueChange={field.onChange} defaultValue={field.value}>
                        <FormControl>
                          <SelectTrigger data-testid="select-integrates-faith">
                            <SelectValue placeholder="Please select..." />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="yes">Yes</SelectItem>
                          <SelectItem value="no">No</SelectItem>
                          <SelectItem value="i-dont-know">I don't know</SelectItem>
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="faithIntegrationEase"
                  render={({ field }) => (
                    <FormItem className="flex flex-col h-full">
                      <FormLabel className="form-label-fixed">Is faith integration easy for you?</FormLabel>
                      <Select onValueChange={field.onChange} defaultValue={field.value}>
                        <FormControl>
                          <SelectTrigger data-testid="select-faith-integration-ease">
                            <SelectValue placeholder="Please select..." />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="easy">Easy</SelectItem>
                          <SelectItem value="hard">Hard</SelectItem>
                          <SelectItem value="i-dont-know">I don't know</SelectItem>
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </div>

              <FormField
                control={form.control}
                name="cause"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Do you have a cause you feel called to?</FormLabel>
                    <FormControl>
                      <Textarea 
                        placeholder="Describe any cause or mission you feel passionate about or called to..."
                        className="h-20 resize-none"
                        {...field}
                        value={field.value || ""} 
                        data-testid="textarea-cause"
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <FormField
                  control={form.control}
                  name="peopleGroup"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Is there a particular people group you feel called to help?</FormLabel>
                      <FormControl>
                        <Input 
